import React, { useState, useEffect, useRef } from 'react';
import { Document, Page, pdfjs } from 'react-pdf';
import 'react-pdf/dist/Page/AnnotationLayer.css';
import 'react-pdf/dist/Page/TextLayer.css';

// 🔑 WORKER PDF.JS - Version Cloudflare (plus fiable)
const WORKER_URL = `https://cdnjs.cloudflare.com/ajax/libs/pdf.js/${pdfjs.version || '3.11.174'}/pdf.worker.min.js`;
pdfjs.GlobalWorkerOptions.workerSrc = WORKER_URL;

interface PDFViewerProps {
  fileUrl: string;
  onDocumentLoad?: (numPages: number) => void;
}

const PDFViewer: React.FC<PDFViewerProps> = ({ fileUrl, onDocumentLoad }) => {
  const [numPages, setNumPages] = useState<number | null>(null);
  const [pageNumber, setPageNumber] = useState(1);
  const [scale, setScale] = useState(1.0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [progress, setProgress] = useState(0);
  const loadTimeout = useRef<NodeJS.Timeout | null>(null);
  const isMounted = useRef(true);
  const retryCount = useRef(0);
  const MAX_RETRIES = 3;

  // Cleanup au démontage
  useEffect(() => {
    return () => {
      isMounted.current = false;
      if (loadTimeout.current) clearTimeout(loadTimeout.current);
    };
  }, []);

  // Réinitialisation à chaque changement de fichier
  useEffect(() => {
    if (loadTimeout.current) clearTimeout(loadTimeout.current);
    
    setLoading(true);
    setError(null);
    setProgress(0);
    setPageNumber(1);
    retryCount.current = 0;
    
    // Timeout de sécurité (20 secondes max)
    loadTimeout.current = setTimeout(() => {
      if (isMounted.current && loading) {
        setError('⏳ Temps de chargement dépassé (20s)\n\n• Vérifiez votre connexion internet\n• Le PDF est-il trop volumineux ?\n• L\'URL est-elle accessible ?');
        setLoading(false);
      }
    }, 20000);
    
    return () => {
      if (loadTimeout.current) clearTimeout(loadTimeout.current);
    };
  }, [fileUrl]);

  const onDocumentSuccess = (pdf: any) => {
    if (!isMounted.current) return;
    if (loadTimeout.current) clearTimeout(loadTimeout.current);
    
    setNumPages(pdf.numPages);
    setLoading(false);
    setError(null);
    setProgress(100);
    
    // Ajuster le zoom selon le nombre de pages
    if (pdf.numPages > 15) setScale(0.8);
    else if (pdf.numPages > 10) setScale(0.9);
    
    if (onDocumentLoad) onDocumentLoad(pdf.numPages);
  };

  const onDocumentProgress = (progressData: any) => {
    if (!isMounted.current) return;
    const percent = Math.round((progressData.loaded / progressData.total) * 100);
    setProgress(percent);
  };

  const onDocumentError = async (err: any) => {
    if (!isMounted.current) return;
    if (loadTimeout.current) clearTimeout(loadTimeout.current);
    
    console.error('❌ Erreur PDF:', err);
    retryCount.current++;
    
    // Tentative de rechargement automatique (max 3 fois)
    if (retryCount.current <= MAX_RETRIES && !err.message?.includes('InvalidPDF')) {
      console.log(`🔄 Tentative de rechargement ${retryCount.current}/${MAX_RETRIES}...`);
      setTimeout(() => {
        setLoading(true);
        setError(null);
      }, 1000 * retryCount.current);
      return;
    }
    
    // Déterminer le message d'erreur approprié
    let message = '📄 Impossible de charger le PDF';
    let details = err.message || 'Erreur inconnue';
    
    if (err.name === 'InvalidPDFException' || err.message?.includes('InvalidPDF')) {
      message = '⚠️ Fichier PDF corrompu ou invalide';
      details = 'Le fichier PDF semble être corrompu ou n\'est pas un PDF valide.';
    } else if (err.name === 'MissingPDFException' || err.status === 404) {
      message = '🔍 PDF introuvable (404)';
      details = 'Le fichier PDF n\'existe pas à cette URL ou a été supprimé.';
    } else if (err.message?.includes('CORS') || err.message?.includes('cross-origin')) {
      message = '🔒 Erreur CORS - Bucket non public';
      details = 'Le bucket Supabase n\'est pas configuré en public.\n\nSolution :\n1. Allez dans Supabase → Storage → document-files\n2. Cliquez sur "Settings"\n3. Activez "Public"\n4. Créez une politique SELECT avec "true"';
    } else if (err.status === 403 || err.message?.includes('403')) {
      message = '🔐 Accès refusé (403)';
      details = 'Le fichier n\'est pas accessible publiquement.\n\nVérifiez :\n• Le bucket est bien public\n• La politique RLS SELECT existe\n• L\'URL du fichier est correcte';
    } else if (err.message?.includes('timeout')) {
      message = '⏱️ Temps d\'attente dépassé';
      details = 'Le serveur met trop de temps à répondre.\n\nEssayez :\n• Vérifier votre connexion\n• Réduire la taille du PDF\n• Recharger la page';
    }
    
    setError(`${message}\n\n${details}`);
    setLoading(false);
    setProgress(0);
  };

  const onSourceError = (err: any) => {
    console.error('❌ Erreur source PDF:', err);
    // Ne pas afficher d'erreur ici, onDocumentError la gérera
  };

  const goToPrevPage = () => {
    setPageNumber(prev => Math.max(prev - 1, 1));
  };

  const goToNextPage = () => {
    setPageNumber(prev => Math.min(prev + 1, numPages || 1));
  };

  const zoomIn = () => {
    setScale(prev => Math.min(prev + 0.2, 3.0));
  };

  const zoomOut = () => {
    setScale(prev => Math.max(prev - 0.2, 0.3));
  };

  const resetZoom = () => {
    setScale(1.0);
  };

  // 🔑 DEBUG : Afficher l'URL et le worker dans la console
  useEffect(() => {
    console.log('🔍 [PDFViewer] URL du fichier:', fileUrl);
    console.log('👷 [PDFViewer] Worker PDF.js:', WORKER_URL);
    console.log('📊 [PDFViewer] Taille estimée:', 'En attente...');
  }, [fileUrl]);

  // 🔑 Vérification de l'accessibilité du fichier
  useEffect(() => {
    if (!fileUrl) return;
    
    const checkFileAccess = async () => {
      try {
        const response = await fetch(fileUrl, { method: 'HEAD', mode: 'cors' });
        
        if (!response.ok) {
          throw new Error(`HTTP ${response.status} ${response.statusText}`);
        }
        
        const contentLength = response.headers.get('content-length');
        const contentType = response.headers.get('content-type');
        
        console.log('✅ [PDFViewer] Fichier accessible');
        console.log('📊 [PDFViewer] Taille:', contentLength ? `${Math.round(parseInt(contentLength) / 1024)} Ko` : 'Inconnue');
        console.log('📄 [PDFViewer] Type:', contentType || 'Inconnu');
        
        if (contentLength && parseInt(contentLength) > 10 * 1024 * 1024) {
          console.warn('⚠️ [PDFViewer] Fichier volumineux (>10 Mo), chargement peut être lent');
        }
      } catch (err) {
        console.error('❌ [PDFViewer] Fichier inaccessible:', err);
        if (isMounted.current) {
          setError(`🔐 Le fichier n'est pas accessible\n\nURL: ${fileUrl}\n\nErreur: ${err instanceof Error ? err.message : 'Inconnue'}\n\nVérifiez que le bucket Supabase est PUBLIC.`);
        }
      }
    };
    
    checkFileAccess();
  }, [fileUrl]);

  return (
    <div className="h-full flex flex-col bg-gray-50 dark:bg-gray-800">
      {/* Barre d'outils */}
      <div className="flex items-center justify-between p-3 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-700/50">
        <div className="flex items-center gap-3">
          <button
            onClick={goToPrevPage}
            disabled={pageNumber <= 1 || loading}
            className={`p-1.5 rounded-md transition-colors ${
              pageNumber <= 1 || loading
                ? 'text-gray-400 cursor-not-allowed'
                : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
            }`}
            title="Page précédente (←)"
          >
            <i className="fas fa-chevron-left"></i>
          </button>
          
          <div className="flex items-center gap-2 text-sm font-medium text-gray-700 dark:text-gray-300">
            <span>Page</span>
            <input
              type="number"
              value={pageNumber}
              onChange={(e) => {
                const page = parseInt(e.target.value);
                if (!isNaN(page) && page >= 1 && page <= (numPages || 1)) {
                  setPageNumber(page);
                }
              }}
              min="1"
              max={numPages || 1}
              disabled={loading}
              className="w-14 text-center px-1.5 py-0.5 border border-gray-300 dark:border-gray-600 rounded text-gray-900 dark:text-white disabled:bg-gray-100 disabled:dark:bg-gray-700 disabled:cursor-not-allowed"
            />
            <span className="text-gray-500 dark:text-gray-400">/</span>
            <span>{numPages || '?'}</span>
          </div>
          
          <button
            onClick={goToNextPage}
            disabled={pageNumber >= (numPages || 1) || loading}
            className={`p-1.5 rounded-md transition-colors ${
              pageNumber >= (numPages || 1) || loading
                ? 'text-gray-400 cursor-not-allowed'
                : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
            }`}
            title="Page suivante (→)"
          >
            <i className="fas fa-chevron-right"></i>
          </button>
        </div>
        
        <div className="flex items-center gap-2">
          <button
            onClick={zoomOut}
            disabled={loading}
            className="p-1.5 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            title="Zoom arrière (-)"
          >
            <i className="fas fa-search-minus"></i>
          </button>
          
          <span className="text-sm font-medium text-gray-700 dark:text-gray-300 min-w-[45px] text-center">
            {Math.round(scale * 100)}%
          </span>
          
          <button
            onClick={zoomIn}
            disabled={loading}
            className="p-1.5 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            title="Zoom avant (+)"
          >
            <i className="fas fa-search-plus"></i>
          </button>
          
          <button
            onClick={resetZoom}
            disabled={loading || scale === 1.0}
            className="p-1.5 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-md transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            title="Zoom 100% (0)"
          >
            <i className="fas fa-expand"></i>
          </button>
        </div>
        
        <div className="flex items-center gap-2">
          <button
            onClick={() => window.open(fileUrl, '_blank')}
            className="px-3 py-1.5 text-sm bg-blue-600 hover:bg-blue-700 text-white rounded-md flex items-center gap-1.5 transition-colors"
            title="Ouvrir dans un nouvel onglet"
          >
            <i className="fas fa-external-link-alt"></i>
            <span className="hidden sm:inline">Ouvrir</span>
          </button>
          
          {loading && (
            <div className="flex items-center gap-2 text-sm text-blue-600 dark:text-blue-400">
              <div className="w-16 bg-gray-200 dark:bg-gray-600 rounded-full h-2">
                <div 
                  className="bg-blue-600 h-2 rounded-full transition-all duration-300" 
                  style={{ width: `${progress}%` }}
                ></div>
              </div>
              <span>{progress}%</span>
            </div>
          )}
        </div>
      </div>
      
      {/* Zone de visualisation */}
      <div className="flex-1 overflow-auto bg-white dark:bg-gray-800 flex items-center justify-center p-4 relative">
        {loading && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/90 dark:bg-gray-800/90 backdrop-blur-sm z-10">
            {/* APRÈS (supprime le warning) */}
<div className="animate-spin rounded-full h-16 w-16 mb-4 border-4 border-transparent border-b-blue-600 border-t-blue-200"></div>
            <p className="text-lg font-medium text-gray-800 dark:text-white mb-2">Chargement du PDF...</p>
            <p className="text-sm text-gray-600 dark:text-gray-400">
              {progress > 0 ? `${progress}% chargé` : 'Connexion au serveur...'}
            </p>
            {progress > 0 && (
              <div className="mt-4 w-64 bg-gray-200 dark:bg-gray-700 rounded-full h-2.5">
                <div 
                  className="bg-blue-600 h-2.5 rounded-full transition-all duration-300" 
                  style={{ width: `${progress}%` }}
                ></div>
              </div>
            )}
          </div>
        )}
        
        {error && (
          <div className="absolute inset-0 flex items-center justify-center p-6 z-10">
            <div className="max-w-2xl w-full bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-xl shadow-lg p-6 text-center">
              <div className="w-16 h-16 bg-red-100 dark:bg-red-900/50 rounded-full flex items-center justify-center mx-auto mb-4">
                <i className="fas fa-exclamation-triangle text-red-600 dark:text-red-400 text-3xl"></i>
              </div>
              <h3 className="text-xl font-bold text-red-800 dark:text-red-200 mb-3">Erreur de chargement</h3>
              <p className="text-red-700 dark:text-red-300 text-sm whitespace-pre-line mb-6 px-4">{error}</p>
              
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3 max-w-md mx-auto">
                <button
                  onClick={() => window.open(fileUrl, '_blank')}
                  className="px-4 py-3 bg-red-600 hover:bg-red-700 text-white rounded-lg font-medium transition-colors flex items-center justify-center gap-2"
                >
                  <i className="fas fa-file-pdf"></i>
                  Ouvrir directement
                </button>
                
                <button
                  onClick={() => {
                    setLoading(true);
                    setError(null);
                    retryCount.current = 0;
                  }}
                  className="px-4 py-3 bg-gray-200 hover:bg-gray-300 dark:bg-gray-700 dark:hover:bg-gray-600 text-gray-800 dark:text-gray-200 rounded-lg font-medium transition-colors flex items-center justify-center gap-2"
                >
                  <i className="fas fa-redo"></i>
                  Réessayer
                </button>
              </div>
              
              <div className="mt-6 pt-6 border-t border-red-200 dark:border-red-800 text-left text-xs text-red-700 dark:text-red-400 bg-red-50 dark:bg-red-900/10 rounded-lg p-4">
                <p className="font-bold mb-2 flex items-center">
                  <i className="fas fa-wrench mr-2"></i>
                  Solutions possibles :
                </p>
                <ul className="list-disc list-inside space-y-1.5">
                  <li>
                    <strong>Vérifiez le bucket Supabase :</strong><br />
                    Storage → document-files → Settings → Public (activé)
                  </li>
                  <li>
                    <strong>Créez une politique RLS :</strong><br />
                    <code className="bg-gray-200 dark:bg-gray-700 px-1.5 py-0.5 rounded">CREATE POLICY "Public read" ON storage.objects FOR SELECT USING (bucket_id = 'document-files');</code>
                  </li>
                  <li>
                    <strong>Testez l'URL :</strong><br />
                    Copiez l'URL du PDF et ouvrez-la dans un nouvel onglet
                  </li>
                  <li>
                    <strong>Vérifiez la taille du PDF :</strong><br />
                    Idéal : &lt; 5 Mo pour un chargement rapide
                  </li>
                </ul>
              </div>
              
              <div className="mt-4 text-xs text-gray-500 dark:text-gray-400">
                <p>
                  <i className="fas fa-info-circle mr-1"></i>
                  Worker PDF.js : <code className="bg-gray-200 dark:bg-gray-700 px-1 py-0.5 rounded">{WORKER_URL}</code>
                </p>
              </div>
            </div>
          </div>
        )}
        
        <Document
          file={fileUrl}
          onLoadSuccess={onDocumentSuccess}
          onLoadProgress={onDocumentProgress}
          onLoadError={onDocumentError}
          onSourceError={onSourceError}
          loading=""
          error=""
          className="max-w-full"
        >
          <Page
            pageNumber={pageNumber}
            scale={scale}
            renderTextLayer={true}
            renderAnnotationLayer={true}
            className="shadow-xl rounded-lg"
            renderMode="canvas"
          />
        </Document>
      </div>
      
      {/* Indicateur en bas */}
      <div className="py-2 px-4 text-center text-xs text-gray-600 dark:text-gray-400 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-700/50">
        {loading && progress === 0 && 'Connexion au serveur...'}
        {loading && progress > 0 && `Chargement : ${progress}%`}
        {error && '❌ Erreur détectée'}
        {!loading && !error && numPages && `✅ PDF chargé • ${numPages} page${numPages > 1 ? 's' : ''} • Zoom : ${Math.round(scale * 100)}%`}
        {!loading && !error && !numPages && '📄 Prêt à charger'}
      </div>
    </div>
  );
};

export default PDFViewer;
